{
  "core_question": "Determine valuation, deal structure, and risk sharing for a US biotech co-developing an oncology asset with an EU pharma.",
  "rationale": "The question requires clinical assessment of program risk and regulatory pathways (healthcare), jurisdictional IP and contractual structuring across US/EU/UK (legal), and financial modeling of rNPV, milestone calibration, and royalty economics (finance).",
  "routes": ["healthcare", "legal", "finance"],
  "sub_questions": {
    "healthcare": "Identify and quantify the primary clinical and regulatory risks associated with a single Phase 3 oncology asset under FDA accelerated approval, and explain how these risks should be incorporated into a valuation model.",
    "legal": "Explain how to structure territorial rights, IP ownership, and milestone payment terms in a co-development deal between a US biotech and an EU pharma, ensuring compliance with US FDA, EMA, UK MHRA, and EU patent laws.",
    "finance": "Outline the steps to calculate the rNPV of a Phase 3 oncology asset for a pre-revenue biotech, including how to incorporate upfront payments, milestone milestones, tiered royalties, and territorial splits into the financial model."
  },
  "requires_recency_disclosure": true,
  "recency_notes": "Potentially stale FDA accelerated approval guidance post-2024; recent EMA/UK MHRA regulatory updates; EU patent law revisions; current market valuations for oncology assets; updated royalty rate benchmarks."
}
